47: std::string cpu_model(void)
48: {
49: 	const std::string content = read_file_content("/proc/cpuinfo");
50: 	if (content.empty())
51: 		return "";
52: 
53: 	std::istringstream stream(content);
54: 	std::string line;
55: 
56: 	while (std::getline(stream, line)) {
57: 		if (line.find("model name") != std::string::npos) {
58: 			const size_t pos = line.find(':');
59: 			if (pos != std::string::npos) {
60: 				std::string model = line.substr(pos + 1);
61: 				/* Trim leading space if any */
62: 				if (!model.empty() && model[0] == ' ')
63: 					model.erase(0, 1);
64: 				return model;
65: 			}
66: 		}
67: 	}
68: 	return "";
69: }
