71: static std::string read_os_release(const std::string &filename)
72: {
73: 	const std::string pname = "PRETTY_NAME=";
74: 	std::string content = read_file_content(filename);
75: 	if (content.empty())
76: 		return "";
77: 
78: 	std::istringstream stream(content);
79: 	std::string line;
80: 	while (std::getline(stream, line)) {
81: 		if (line.starts_with(pname)) {
82: 			size_t pos = line.find('=');
83: 			if (pos == std::string::npos)
84: 				break;
85: 			std::string os = line.substr(pos + 1);
86: 			if (os.length() >= 2 && (os.front() == '"' || os.front() == '\'')) {
87: 				os.erase(0, 1);
88: 				size_t end_pos = os.find_first_of("\"\'");
89: 				if (end_pos != std::string::npos)
90: 					os.erase(end_pos);
91: 			}
92: 			return os;
93: 		}
94: 	}
95: 	return "";
96: }
