99: static void system_info(void)
100: {
101: 	std::string str;
102: 	const auto now = std::chrono::system_clock::now();
103: 
104: 	/* div attr css_class and css_id */
105: 	tag_attr div_attr;
106: 	init_div(&div_attr, "sys_info", "");
107: 
108: 	/* Set Table attributes, rows, and cols */
109: 	table_attributes sys_table;
110: 	init_top_table_attr(&sys_table, 5, 2);
111: 
112: 	/* Set Title attributes */
113: 	tag_attr title_attr;
114:         init_title_attr(&title_attr);
115: 
116: 	/* Set array of data in row Major order */
117: 	std::vector<std::string> system_data(sys_table.rows * sys_table.cols);
118: 	system_data[0]=__("PowerTOP Version");
119: 	system_data[1] = pt_format(_("{} ran at {}"), PACKAGE_VERSION, get_time_string("%c", now));
120: 
121: 	str = read_sysfs_string("/proc/version");
122: 	size_t  found = str.find(" ");
123: 	found = str.find(" ", found+1);
124: 	found = str.find(" ", found+1);
125: 	str = str.substr(0,found);
126: 	system_data[2]=__("Kernel Version");
127: 	system_data[3]=str;
128: 
129: 	str  = read_sysfs_string("/sys/devices/virtual/dmi/id/board_vendor");
130: 	system_data[4]=__("System Name");
131: 	system_data[5]= str;
132: 	system_data[5] += read_sysfs_string("/sys/devices/virtual/dmi/id/board_name");
133: 	system_data[5] += read_sysfs_string("/sys/devices/virtual/dmi/id/product_version");
134: 
135: 	system_data[6]=__("CPU Information");
136: 	system_data[7] = std::to_string(sysconf(_SC_NPROCESSORS_ONLN));
137: 	system_data[7] += cpu_model();
138: 
139: 	str = read_sysfs_string("/etc/system-release");
140: 	if (str.length() < 1)
141: 	str = read_sysfs_string("/etc/redhat-release");
142: 	if (str.length() < 1)
143: 	str = read_os_release("/etc/os-release");
144: 
145: 	system_data[8]=__("OS Information");
146: 	system_data[9]=str;
147: 
148: 	/* Report Output */
149: 	report.add_header();
150: 	report.add_logo();
151: 	report.add_div(&div_attr);
152: 	report.add_title(&title_attr, __("System Information"));
153: 	report.add_table(system_data, &sys_table);
154: 	report.end_header();
155: 	report.end_div();
156: 	report.add_navigation();
157: }
