159: void init_report_output(const std::string &filename_str, int iterations)
160: {
161: 	size_t period;
162: 
163: 	if (iterations == 1)
164: 		reportout.filename = filename_str;
165: 	else
166: 	{
167: 		period = filename_str.find_last_of(".");
168: 		if (period == std::string::npos)
169: 			period = filename_str.length();
170: 
171: 		const auto stamp = std::chrono::system_clock::now();
172: 		reportout.filename = std::format("{}-{}{}",
173: 			filename_str.substr(0, period),
174: 			get_time_string("%Y%m%d-%H%M%S", stamp),
175: 			filename_str.substr(period));
176: 	}
177: 
178: 	reportout.report_file.open(reportout.filename, std::ios::out);
179: 	if (!reportout.report_file) {
180: 		fprintf(stderr, _("Cannot open output file %s (%s)\n"),
181: 			reportout.filename.c_str(), strerror(errno));
182: 	}
183: 
184: 	report.set_type(reporttype);
185: 	system_info();
186: }
187: 
188: void finish_report_output(void)
189: {
190: 	if (reporttype == REPORT_OFF)
191: 		return;
192: 
193: 	report.finish_report();
194: 	if (reportout.report_file.is_open())
195: 	{
196: 		fprintf(stderr, _("PowerTOP outputting using base filename %s\n"), reportout.filename.c_str());
197: 		reportout.report_file << report.get_result();
198: 		reportout.report_file.flush();
199: 		reportout.report_file.close();
200: 	}
201: 	report.clear_result();
202: }

