127: /* Escape a string value for inclusion in a JSON string literal. */
128: inline std::string pt_json_escape(const std::string &s)
129: {
130: 	std::string out;
131: 	out.reserve(s.size());
132: 	for (unsigned char c : s) {
133: 		if      (c == '"')  out += "\\\"";
134: 		else if (c == '\\') out += "\\\\";
135: 		else if (c == '\n') out += "\\n";
136: 		else if (c == '\r') out += "\\r";
137: 		else if (c == '\t') out += "\\t";
138: 		else                out += c;
139: 	}
140: 	return out;
141: }
