196: /*
197:  * pt_json_array — serializes a vector of pointers or smart pointers whose
198:  * pointees have a serialize() const method. Returns a JSON array string "[...]".
199:  */
200: template<typename T>
201: inline std::string pt_json_array(const std::vector<T> &vec)
202: {
203: 	std::string out = "[";
204: 	for (size_t i = 0; i < vec.size(); ++i) {
205: 		out += vec[i]->serialize();
206: 		if (i + 1 < vec.size())
207: 			out += ",";
208: 	}
209: 	out += "]";
210: 	return out;
211: }
