213: /*
214:  * Serialization macros.
215:  *
216:  * Usage in serialize() / collect_json_fields():
217:  *
218:  *   std::string serialize() const {
219:  *       JSON_START();
220:  *       JSON_FIELD(my_member);          // key = "my_member"
221:  *       JSON_KV("key", some_method());  // explicit key
222:  *       JSON_ARRAY("items", vec_);      // vector<T*> whose T has serialize()
223:  *       JSON_END();
224:  *   }
225:  *
226:  * JSON_START() declares the local accumulator string _js.
227:  * JSON_END() appends a sentinel field "_end":0 (avoids trailing-comma
228:  * handling) then closes the object and returns it.
229:  *
230:  * For class hierarchies, override collect_json_fields(std::string &_js) and
231:  * call the parent version first.  serialize() in the base calls
232:  * collect_json_fields() then JSON_END().
233:  */
234: #define JSON_START()      std::string _js = "{"
235: #define JSON_FIELD(x)     _js += pt_json_kv(#x, (x)) + ","
236: #define JSON_KV(k, v)     _js += pt_json_kv((k), (v)) + ","
237: #define JSON_ARRAY(k, v)  _js += "\"" k "\":" + pt_json_array(v) + ","
238: #define JSON_END()        return _js + "\"_end\":0}"
