119: std::string
120: double_to_string(const double dval)
121: {
122: 	std::ostringstream dtmp;
123: 	dtmp << dval;
124: 	std::string str = dtmp.str();
125: 	const auto dot = str.find('.');
126: 	if (dot != std::string::npos)
127: 		str = str.substr(0, dot + 2);
128: 	return str;
129: }
